import os

def read_file_from_dir(filename: str, dir_path: str) -> str:
    try:
        dir_path_abs = os.path.abspath(dir_path)
        full_path = os.path.join(dir_path_abs, filename)
        full_path_abs = os.path.abspath(full_path)
        if not full_path_abs.startswith(dir_path_abs):
            return ""
        if not os.path.isfile(full_path_abs):
            return ""
        with open(full_path_abs, 'r') as f:
            content = f.read()
        return content
    except Exception:
        return ""

