import shlex

def executeCommand():
    command = input("Enter command: ")
    forbidden_chars = {';', '|', '&', '>', '<', '(', ')', '{', '}', '$', '`'}
    if any(char in command for char in forbidden_chars):
        raise ValueError("Invalid command")
    args = shlex.split(command)
    subprocess.run(args, check=True)

